Forger使用three.js加入光影效果需要以下几个步骤：

1. 引入three.js库
```
<script src="js/three.min.js"></script>
```

2. 创建场景、相机和渲染器
```
var scene = new THREE.Scene();
var camera = new THREE.PerspectiveCamera(75, window.innerWidth/window.innerHeight, 0.1, 1000);
var renderer = new THREE.WebGLRenderer();
renderer.setSize(window.innerWidth, window.innerHeight);
document.body.appendChild(renderer.domElement);
```

3. 添加光源
```
var light = new THREE.PointLight(0xffffff, 1, 100);
light.position.set(0, 0, 0);
scene.add(light);
```

4. 创建物体并设置其材质和纹理
```
var geometry = new THREE.BoxGeometry(1, 1, 1);
var material = new THREE.MeshPhongMaterial({ color: 0xffffff });
var cube = new THREE.Mesh(geometry, material);
var textureLoader = new THREE.TextureLoader();
textureLoader.load('textures/texture.jpg', function (texture) {
    material.map = texture;
    material.needsUpdate = true;
});
scene.add(cube);
```

5. 创建阴影
```
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
light.castShadow = true;
cube.castShadow = true;
```

6. 渲染场景
```
function animate() {
    requestAnimationFrame(animate);
    cube.rotation.x += 0.01;
    cube.rotation.y += 0.01;
    renderer.render(scene, camera);
}
animate();
```
以上这些步骤可以实现基本的光影效果，如果需要更加细致的调整可以根据具体情况进行修改。

Forge中加入光影效果需要以下几个步骤：

1. 初始化Viewer
```
var options = {
    env: 'AutodeskProduction',
    accessToken: 'YOUR_ACCESS_TOKEN'
};
var viewer = new Autodesk.Viewing.Private.GuiViewer3D(document.getElementById('forgeViewer'), options);
```

2. 加载模型
```
var urn = 'URN_OF_YOUR_MODEL';
Autodesk.Viewing.Initializer(options, function() {
    viewer.initialize();
    Autodesk.Viewing.Document.load('urn:' + urn, function(document) {
        var geometryItems = Autodesk.Viewing.Document.getSubItemsWithProperties(document.getRootItem(), { type: 'geometry' });
        viewer.loadModel(document.getViewablePath(geometryItems[0]));
    }, function() {
        console.log('Failed to load document');
    });
});
```

3. 添加光源
```
var light = new THREE.PointLight(0xffffff, 1);
light.position.set(0, 0, 0);
viewer.impl.scene.add(light);
```

4. 创建物体并设置其材质和纹理
```
var material = new THREE.MeshPhongMaterial({ color: 0xffffff });
var textureLoader = new THREE.TextureLoader();
textureLoader.load('textures/texture.jpg', function (texture) {
    material.map = texture;
    material.needsUpdate = true;
});
viewer.impl.createOverlayScene('customOverlay');
var box = new THREE.Mesh(new THREE.BoxGeometry(1, 1, 1), material);
box.position.set(0, 0.5, 0);
viewer.impl.addOverlay('customOverlay', box);
```

5. 创建阴影
```
viewer.impl.renderer.shadowMap.enabled = true;
viewer.impl.renderer.shadowMap.type = THREE.PCFSoftShadowMap;
light.castShadow = true;
box.castShadow = true;
```

6. 渲染场景
```
viewer.addEventListener(Autodesk.Viewing.GEOMETRY_LOADED_EVENT, function() {
    viewer.impl.createScene();
    viewer.impl.invalidate(true);
});
```
以上是一个简单的例子，可以将其作为参考，并根据实际需求进行修改。

Forge可以使用Viewer来实现3D模型的可视化效果，使用Viewer需要以下几个步骤：

1. 创建Viewer对象
```
var options = {
    env: 'AutodeskProduction',
    accessToken: 'YOUR_ACCESS_TOKEN'
};
var viewer = new Autodesk.Viewing.Private.GuiViewer3D(document.getElementById('forgeViewer'), options);
```

2. 加载模型
```
var urn = 'URN_OF_YOUR_MODEL';
Autodesk.Viewing.Initializer(options, function() {
    viewer.initialize();
    Autodesk.Viewing.Document.load('urn:' + urn, function(document) {
        var geometryItems = Autodesk.Viewing.Document.getSubItemsWithProperties(document.getRootItem(), { type: 'geometry' });
        viewer.loadModel(document.getViewablePath(geometryItems[0]));
    }, function() {
        console.log('Failed to load document');
    });
});
```

3. 渲染场景
```
viewer.addEventListener(Autodesk.Viewing.GEOMETRY_LOADED_EVENT, function() {
    viewer.fitToView();
});
```

以上是一个简单的例子，可以将其作为参考，并根据实际需求进行修改。Viewer还支持多种功能，如红线标记、构件选择和属性查看、构件分类和搜索、多种视角和交互方式、多种组件和插件等，可以根据需要进行开发和集成。

在Forge Viewer中选中某个构件并且拉近距离，可以使用`viewer.fitToView`方法，高亮显示可以使用`viewer.setThemingColor`方法。

以下是一个基本实现：

```
// 定义选中构件时的回调函数
var onSelectionChanged = function (event) {
    var selection = event.dbIdArray;
    if (selection.length > 0) {
        // 选中构件
        viewer.setThemingColor(selection, new THREE.Color(0xff0000));
        // 设置对应的物体尺寸
        viewer.fitToView(selection);
    }
};
// 添加选中构件时的监听事件
viewer.addEventListener(Autodesk.Viewing.SELECTION_CHANGED_EVENT, onSelectionChanged);
```

通过`setThemingColor`方法设置选中构件的高亮颜色，通过`fitToView`方法将选中构件自适应场景视角。可根据实际需求调整高亮颜色和视角。
